const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(helmet());
app.use(express.json({ limit: '100kb' }));

const client = new Client({ node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200' });

// Whitelist of allowed indices
const ALLOWED_INDICES = new Set([
  'public-logs',
  'analytics-data',
  'product-catalog'
]);

// Whitelist of allowed query types
const ALLOWED_QUERY_TYPES = new Set([
  'match',
  'term',
  'range',
  'bool',
  'match_all'
]);

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests'
});

app.use('/api/search', limiter);

// Authentication middleware (implement based on your auth system)
function authenticate(req, res, next) {
  const apiKey = req.headers['x-api-key'];
  
  if (!apiKey || apiKey !== process.env.ADMIN_API_KEY) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  
  next();
}

// Authorization middleware
function authorize(req, res, next) {
  const userRole = req.headers['x-user-role'];
  
  if (userRole !== 'admin') {
    return res.status(403).json({ error: 'Forbidden - Admin access required' });
  }
  
  next();
}

// Validate index name
function validateIndex(indexName) {
  if (!indexName || typeof indexName !== 'string') {
    return false;
  }
  
  if (!ALLOWED_INDICES.has(indexName)) {
    return false;
  }
  
  if (!/^[a-z0-9_-]+$/.test(indexName)) {
    return false;
  }
  
  return true;
}

// Validate query structure
function validateQuery(query) {
  if (!query || typeof query !== 'object') {
    return { valid: false, error: 'Invalid query format' };
  }
  
  // Prevent script execution
  if (JSON.stringify(query).includes('script')) {
    return { valid: false, error: 'Script queries are not allowed' };
  }
  
  // Check query depth to prevent complex nested queries
  const depth = getObjectDepth(query);
  if (depth > 5) {
    return { valid: false, error: 'Query too complex' };
  }
  
  // Validate query types
  const queryTypes = extractQueryTypes(query);
  for (const type of queryTypes) {
    if (!ALLOWED_QUERY_TYPES.has(type)) {
      return { valid: false, error: `Query type '${type}' not allowed` };
    }
  }
  
  return { valid: true };
}

function getObjectDepth(obj, depth = 0) {
  if (typeof obj !== 'object' || obj === null) {
    return depth;
  }
  
  const depths = Object.values(obj).map(v => getObjectDepth(v, depth + 1));
  return Math.max(depth, ...depths);
}

function extractQueryTypes(obj, types = new Set()) {
  if (typeof obj !== 'object' || obj === null) {
    return types;
  }
  
  for (const [key, value] of Object.entries(obj)) {
    if (ALLOWED_QUERY_TYPES.has(key)) {
      types.add(key);
    }
    if (typeof value === 'object') {
      extractQueryTypes(value, types);
    }
  }
  
  return types;
}

// Sanitize query to limit result size
function sanitizeQuery(query) {
  const sanitized = { ...query };
  
  if (!sanitized.size || sanitized.size > 100) {
    sanitized.size = 100;
  }
  
  if (!sanitized.from) {
    sanitized.from = 0;
  }
  
  if (sanitized.from > 10000) {
    sanitized.from = 10000;
  }
  
  return sanitized;
}

app.post('/api/search/:index', authenticate, authorize, async (req, res) => {
  try {
    const indexName = req.params.index;
    const query = req.body.query;
    
    // Validate index
    if (!validateIndex(indexName)) {
      return res.status(400).json({ 
        error: 'Invalid or unauthorized index',
        allowedIndices: Array.from(ALLOWED_INDICES)
      });
    }
    
    // Validate query
    const validation = validateQuery(query);
    if (!validation.valid) {
      return res.status(400).json({ error: validation.error });
    }
    
    // Sanitize query
    const sanitizedQuery = sanitizeQuery(query);
    
    // Execute search with timeout
    const result = await Promise.race([
      client.search({
        index: indexName,
        body: sanitizedQuery,
        _source_excludes: ['password', 'secret', 'token', 'apiKey', 'ssn', 'creditCard']
      }),
      new Promise((_, reject) => 
        setTimeout(() => reject(new Error('Query timeout')), 5000)
      )
    ]);
    
    // Log the query for audit
    console.log(`[AUDIT] User queried index: ${indexName}, query:`, JSON.stringify(sanitizedQuery));
    
    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      took: result.took
    });
    
  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({ 
      error: 'Search failed',
      message: error.message 
    });
  }
});

// Health check endpoint
app.get('/health', async (req, res) => {
  try {
    await client.ping();
    res.json({ status: 'healthy' });
  } catch (error) {
    res.status(503).json({ status: 'unhealthy' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Secure Elasticsearch API running on port ${PORT}`);
});